import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    """Run at most *max_concurrent* tasks at a time.

    Each callable in *tasks* is an async zero-argument function.  No more
    than *max_concurrent* of them execute simultaneously.

    If the coroutine is cancelled (e.g. via SIGINT through
    :func:`asyncio.run`), tasks that have already started are allowed to
    finish their cleanup code (``try`` / ``finally``, context manager
    ``__aexit__``, etc.).  Tasks that have not yet been started are
    **never** launched after cancellation begins.
    """
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be positive")

    remaining = iter(tasks)

    # Tasks that have entered ``await task_fn()`` — i.e. truly started.
    running: set[asyncio.Task[None]] = set()

    async def _run(task_fn: Callable[[], Awaitable[None]]) -> None:
        """Execute *task_fn* and register in *running*."""
        me = asyncio.current_task()
        running.add(me)
        try:
            await task_fn()
        finally:
            running.discard(me)

    # ---- start the first wave ------------------------------------------
    active: list[asyncio.Task[None]] = []
    for _ in range(max_concurrent):
        try:
            fn = next(remaining)
        except StopIteration:
            break
        active.append(asyncio.create_task(_run(fn)))

    # ---- main event loop -----------------------------------------------
    try:
        while active:
            done, _ = await asyncio.wait(
                active,
                return_when=asyncio.FIRST_COMPLETED,
            )
            # Suppress "Task exception was never retrieved" warnings.
            for t in done:
                try:
                    t.result()
                except BaseException:
                    pass

            # Prune finished tasks and launch replacements up to the limit.
            active = [t for t in active if not t.done()]

            for _ in range(len(done)):
                try:
                    fn = next(remaining)
                except StopIteration:
                    break
                active.append(asyncio.create_task(_run(fn)))

    except asyncio.CancelledError:
        # ---- cancellation: drain running tasks -------------------------
        # The caller (e.g. asyncio.run after SIGINT) cancelled *us*.
        # Let tasks that have already started finish their cleanup, and
        # do NOT launch any more tasks from *remaining*.

        if running:
            current = asyncio.current_task()
            # Python 3.9+: clear our own cancellation flag so that
            # the ``await`` below does not immediately re-raise.
            try:
                while current.uncancel():
                    pass
            except AttributeError:
                pass
            try:
                await asyncio.wait(list(running))
            except asyncio.CancelledError:
                # A further cancellation while waiting — move on.
                pass
        raise
